const API='';
let currentRoomID=null,wsHandle=null,rooms=[],providers=[],personas=[],folders=[],templates=[];
let editingRoomID=null,editingProviderID=null,editingPersonaID=null,currentFolderFilter=null;
let editingAgentID=null,editingObserverID=null;
let activeAgentContext=null;
let observerChatState={roomID:null,observerID:null};
let observerDragState={dragging:false,offsetX:0,offsetY:0};
let observerFabState={dragging:false,moved:false,offsetX:0,offsetY:0};
let observerAutoCreatePendingRoomID=null;
let contextMenuHoldUntil=0;
let observerFabClickTimer=null;
let observerFabDoubleLock=false;
let panelResizeState={target:null,startX:0,startWidth:0,minWidth:0,maxWidth:0};
const agentColorCache={};
function wsDebugEnabled(){return localStorage.getItem('ws_debug')==='1'||window.__WS_DEBUG__===true;}
function wsDebugLog(stage,ev){if(!wsDebugEnabled())return;try{const roomID=ev&&ev.payload&&(ev.payload.room_id||ev.payload.id||'');const msgID=ev&&ev.payload&&ev.payload.id?ev.payload.id:'';console.log(`[WS-DEBUG] ${stage} type=${ev&&ev.type?ev.type:'unknown'} room=${roomID} msg=${msgID}`,ev);}catch(_){}}
window.setWSDebug=function(on){const v=!!on;localStorage.setItem('ws_debug',v?'1':'0');window.__WS_DEBUG__=v;console.log('[WS-DEBUG] '+(v?'enabled':'disabled'));};
function toggleWSDebugFromUI(){const next=!wsDebugEnabled();window.setWSDebug(next);const btn=document.getElementById('btn-ws-debug');if(btn)btn.textContent=next?'WS调试:开':'WS调试:关';notify(next?'WS详细日志已开启（查看控制台）':'WS详细日志已关闭');}
function showPage(p){document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));document.querySelectorAll('.tab-btn').forEach(x=>x.classList.remove('active'));document.getElementById('page-'+p).classList.add('active');document.getElementById('tab-'+p).classList.add('active');if(p==='providers')loadProviders();if(p==='personas')loadPersonasPage();if(p==='templates')loadTemplates();}
function notify(msg,type='success'){const el=document.createElement('div');el.className='notif '+type;el.textContent=msg;document.body.appendChild(el);setTimeout(()=>el.remove(),3500);}
function openModal(id){document.getElementById(id).classList.add('open');}
function closeModal(id){document.getElementById(id).classList.remove('open');}
function showConfirm(msg,onOk){document.getElementById('confirm-msg').textContent=msg;document.getElementById('modal-confirm').classList.add('open');document.getElementById('confirm-ok-btn').onclick=()=>{document.getElementById('modal-confirm').classList.remove('open');onOk();};}
function escHtml(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function getSpeakerRole(msg){const room=rooms.find(r=>r.id===currentRoomID);const agents=(room&&room.agents)||[];const a=agents.find(x=>x.id===msg.agent_id||x.name===msg.agent_name);if(!a)return {cls:'',tag:''};if(a.is_referee)return {cls:' referee-speak',tag:'<span class="msg-role-tag referee">裁判</span>'};if(a.is_assistant)return {cls:' assistant-speak',tag:'<span class="msg-role-tag assistant">裁判辅助</span>'};return {cls:'',tag:''};}
async function apiFetch(path,opts={}){const r=await fetch(API+path,{headers:{'Content-Type':'application/json'},...opts});if(r.status===204)return null;const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.error||r.statusText);return d;}
async function loadRooms(){try{rooms=await apiFetch('/api/rooms')||[];renderRoomList();if(currentRoomID){const r=rooms.find(x=>x.id===currentRoomID);if(r)renderRoomView(r);}}catch(e){notify('加载房间失败: '+e.message,'error');}}
function renderRoomList(){const list=document.getElementById('room-list');if(!rooms.length){list.innerHTML='<div style="padding:16px;color:var(--text-muted);font-size:12px;text-align:center">暂无房间</div>';return;}list.innerHTML=rooms.map(r=>{const sc=r.stop_condition?`<span class="stop-cond-badge">&gt; ${escHtml(r.stop_condition)}</span>`:'';return `<div class="room-item ${r.id===currentRoomID?'active':''}" onclick="selectRoom('${r.id}')"><div class="room-item-name"><div class="room-status-dot ${r.is_running?'running':''}"></div>${escHtml(r.name)}${sc}</div><div class="room-item-meta">${escHtml(r.topic||'暂无话题')} &middot; ${r.agents?r.agents.length:0} AI</div><div class="room-item-actions"><button class="room-action-btn" onclick="event.stopPropagation();cloneRoom('${r.id}')">复制</button><button class="room-action-btn" onclick="event.stopPropagation();exportRoom('${r.id}','markdown')">MD</button><button class="room-action-btn" onclick="event.stopPropagation();exportRoom('${r.id}','json')">JSON</button></div></div>`;}).join('');}
async function selectRoom(id){currentRoomID=id;showPage('chat');renderRoomList();try{const room=await apiFetch('/api/rooms/'+id);renderRoomView(room);connectWS(id);}catch(e){notify('加载失败: '+e.message,'error');}}
function renderRoomView(room){document.getElementById('no-room-view').style.display='none';const rv=document.getElementById('room-view');rv.style.display='flex';document.getElementById('room-title').textContent=room.name;const topicEl=document.getElementById('room-topic-display');topicEl.textContent=room.topic||'';if(room.stop_condition)topicEl.textContent+=' | 停止: '+room.stop_condition;const bs=document.getElementById('btn-start'),bp=document.getElementById('btn-stop'),br=document.getElementById('btn-restart');if(room.is_running){bs.style.display='none';bp.style.display='';if(br)br.style.display='none';}else{bs.style.display='';bp.style.display='none';if(br)br.style.display='';}renderMessages(room.messages||[]);renderAgents(room.agents||[],room);ensureDefaultObserver(room);updateStatusBar(room);}
function renderMessages(msgs){const wrap=document.getElementById('messages');if(!msgs.length){wrap.innerHTML='<div class="empty-state"><div class="empty-text">暂无消息，启动聊天室开始讨论</div></div>';return;}wrap.innerHTML=msgs.map((m,i)=>{if(m.is_system||m.is_private){const isReferee=m.is_private?true:(m.agent_name&&m.agent_name!=='系统'&&m.agent_name!=='系统指令');const cls=isReferee?'referee-cmd':'';const icon=m.is_private?'🔒 ':((isReferee?'':'⚡ '));return `<div class="msg-system-block ${cls}">${icon}${escHtml(m.content)}</div>`;}const color=agentColorCache[m.agent_id]||m.avatar_color||'#0ea5e9';const av=m.avatar_image?`<img src="${m.avatar_image}" />`:(m.agent_name||'?').slice(0,2).toUpperCase();const tok=m.token_count?`<span class="msg-tokens">${m.token_count}t</span>`:'';const numLabel=m.agent_index?`#${m.agent_index}`:`#${i+1}`;const roleMeta=getSpeakerRole(m);return `<div class="msg-bubble"><div class="msg-avatar" style="background:${color}">${av}</div><div class="msg-body"><div class="msg-meta"><span class="msg-index">${numLabel}</span><span class="msg-name" style="color:${color}">${escHtml(m.agent_name)}</span>${roleMeta.tag}<span class="msg-time">${m.timestamp?new Date(m.timestamp).toLocaleTimeString():''}</span>${tok}</div><div class="msg-content${roleMeta.cls}">${escHtml(m.content)}</div></div></div>`;}).join('');wrap.scrollTop=wrap.scrollHeight;}
function appendMessage(msg){const wrap=document.getElementById('messages');const empty=wrap.querySelector('.empty-state');if(empty)empty.remove();const shouldStickToBottom=(wrap.scrollHeight-wrap.scrollTop-wrap.clientHeight)<80;const last=wrap.lastElementChild;if(last&&msg){const sig=(msg.is_system||msg.is_private)?`sys|${msg.agent_name||''}|${msg.content||''}`:`msg|${msg.agent_id||''}|${msg.content||''}|${msg.timestamp||''}`;if(last.getAttribute('data-sig')===sig){return;}}const color=agentColorCache[msg.agent_id]||msg.avatar_color||'#0ea5e9';if(msg.agent_id&&msg.avatar_color)agentColorCache[msg.agent_id]=msg.avatar_color;const el=document.createElement('div');if(msg.is_system||msg.is_private){const isReferee=msg.is_private?true:(msg.agent_name&&msg.agent_name!=='系统'&&msg.agent_name!=='系统指令');const cls=isReferee?'referee-cmd':'';const icon=msg.is_private?'🔒 ':((isReferee?'':'⚡ '));el.className='msg-system-block '+cls;el.textContent='';el.innerHTML=icon+escHtml(msg.content);}else{if(msg.video_url)playVideoBackdrop(msg.video_url);el.className='msg-bubble';const av=msg.avatar_image?`<img src="${msg.avatar_image}" />`:(msg.agent_name||'?').slice(0,2).toUpperCase();const tok=msg.token_count?`<span class="msg-tokens">${msg.token_count}t</span>`:'';const numLabel=msg.agent_index?`#${msg.agent_index}`:'';const roleMeta=getSpeakerRole(msg);el.innerHTML=`<div class="msg-avatar" style="background:${color}">${av}</div><div class="msg-body"><div class="msg-meta"><span class="msg-index">${numLabel}</span><span class="msg-name" style="color:${color}">${escHtml(msg.agent_name)}</span>${roleMeta.tag}<span class="msg-time">${msg.timestamp?new Date(msg.timestamp).toLocaleTimeString():''}</span>${tok}</div><div class="msg-content${roleMeta.cls}">${escHtml(msg.content)}</div></div>`;}const sig=(msg.is_system||msg.is_private)?`sys|${msg.agent_name||''}|${msg.content||''}`:`msg|${msg.agent_id||''}|${msg.content||''}|${msg.timestamp||''}`;el.setAttribute('data-sig',sig);wrap.appendChild(el);if(shouldStickToBottom){wrap.scrollTop=wrap.scrollHeight;}}
function playVideoBackdrop(url){const bd=document.getElementById('video-backdrop');const vid=document.getElementById('backdrop-video');vid.src=url;bd.classList.add('active');vid.play();vid.onended=()=>{bd.classList.remove('active');vid.src='';}}
function renderAgents(agents,room){const list=document.getElementById('agents-list');const referee=agents.find(a=>a.is_referee);const assistants=agents.filter(a=>a.is_assistant&&!a.is_referee&&!a.is_observer);const normals=agents.filter(a=>!a.is_referee&&!a.is_observer&&!a.is_assistant);const buildCard=(a,i,roleType='normal')=>{const isReferee=roleType==='referee';const isAssistant=roleType==='assistant';const color=a.avatar_color||(isReferee||isAssistant?'#7c3aed':'#0ea5e9');agentColorCache[a.id]=color;const av=a.avatar_image?`<img src="${a.avatar_image}" />`:(a.name||'?').slice(0,2).toUpperCase();const agentNum=a.index||i+1;const badge=isAssistant?' <span class="assistant-badge">辅助</span>':(isReferee?' <span class="referee-badge">裁判</span>':'');const sub=isAssistant?'裁判辅助角色':(isReferee?'讨论裁判与调度':'普通角色');const cls=isReferee?'referee-chief':(isAssistant?'referee':'');return `<div class="agent-card ${cls}" data-room-id="${room.id}" data-agent-id="${a.id}" data-role-type="${roleType}" oncontextmenu="openAgentContextMenu(event,'${room.id}','${a.id}','${roleType}')" ondblclick="openAgentContextMenuByDouble('${room.id}','${a.id}','${roleType}',event,this)"><button class="agent-del" onclick="removeAgent('${room.id}','${a.id}')" title="移除">&#x2715;</button><div class="agent-avatar" style="background:${color}">${av}</div><span class="agent-num">#${agentNum}</span><div class="agent-info"><div class="agent-name">${escHtml(a.name)}${badge}</div><div class="agent-provider">${sub}</div></div></div>`;};const refereeHtml=referee?`<div class="agent-section-title">裁判</div>${buildCard(referee,0,'referee')}`:'';const assistantHtml=assistants.length?`<div class="agent-section-title">裁判辅助</div>${assistants.map((a,i)=>buildCard(a,i,'assistant')).join('')}`:'';const normalHtml=normals.length?`<div class="agent-section-title">普通角色</div>${normals.map((a,i)=>buildCard(a,i,'normal')).join('')}`:'';list.innerHTML=refereeHtml+assistantHtml+normalHtml;}
function getObserverAgent(room){if(!room||!room.agents)return null;return room.agents.find(a=>a.is_observer)||null;}
function ensureDefaultObserver(room){const fab=document.getElementById('observer-fab');if(!fab)return;const observer=getObserverAgent(room);if(observer){observerAutoCreatePendingRoomID=null;const win=document.getElementById('observer-chat-float');const chatting=win&&win.style.display==='flex';fab.style.display=chatting?'none':'flex';if(!observerChatState.observerID||observerChatState.roomID!==room.id){observerChatState={roomID:room.id,observerID:observer.id};}return;}fab.style.display='none';if(!room||!room.id)return;if(observerAutoCreatePendingRoomID===room.id)return;if(providers.length===0)return;const providerID=providers[0].id;observerAutoCreatePendingRoomID=room.id;apiFetch('/api/rooms/'+room.id+'/agents',{method:'POST',body:JSON.stringify({name:'旁观者',provider_id:providerID,personality:'请保持中立，重点提炼讨论脉络与分歧点。',avatar_color:'#7c3aed',is_observer:true})}).then(async()=>{const fullRoom=await apiFetch('/api/rooms/'+room.id);const idx=rooms.findIndex(r=>r.id===room.id);if(idx>=0)rooms[idx]=fullRoom;else rooms.push(fullRoom);if(currentRoomID===room.id){renderRoomView(fullRoom);}renderRoomList();}).catch(()=>{}).finally(()=>{if(observerAutoCreatePendingRoomID===room.id){observerAutoCreatePendingRoomID=null;}});}
function openObserverChat(){if(!currentRoomID){notify('请先选择房间','error');return;}const room=rooms.find(r=>r.id===currentRoomID);const observer=getObserverAgent(room);if(!observer){notify('旁观者尚未就绪','error');return;}observerChatState={roomID:currentRoomID,observerID:observer.id};const fab=document.getElementById('observer-fab');if(fab)fab.style.display='none';const win=document.getElementById('observer-chat-float');if(win){win.style.display='flex';}document.getElementById('observer-chat-log').innerHTML='';document.getElementById('observer-chat-input').value='';}
function startObserverFabDrag(ev){if(ev.button!==0)return;const fab=document.getElementById('observer-fab');if(!fab)return;observerFabState.dragging=true;observerFabState.moved=false;observerFabState.offsetX=ev.clientX-fab.offsetLeft;observerFabState.offsetY=ev.clientY-fab.offsetTop;ev.preventDefault();}
function onObserverFabDrag(ev){if(!observerFabState.dragging)return;const fab=document.getElementById('observer-fab');if(!fab)return;if(Math.abs(ev.movementX)+Math.abs(ev.movementY)>0){observerFabState.moved=true;}const maxX=Math.max(0,window.innerWidth-fab.offsetWidth);const maxY=Math.max(0,window.innerHeight-fab.offsetHeight);const x=Math.min(maxX,Math.max(0,ev.clientX-observerFabState.offsetX));const y=Math.min(maxY,Math.max(0,ev.clientY-observerFabState.offsetY));fab.style.left=x+'px';fab.style.top=y+'px';fab.style.right='auto';fab.style.bottom='auto';}
function endObserverFabDrag(){if(!observerFabState.dragging)return;observerFabState.dragging=false;setTimeout(()=>{observerFabState.moved=false;},120);}
function clickObserverFab(){if(observerFabState.moved||observerFabDoubleLock)return;if(observerFabClickTimer){clearTimeout(observerFabClickTimer);}observerFabClickTimer=setTimeout(()=>{openObserverChat();observerFabClickTimer=null;},220);}
function dblclickObserverFab(ev){if(ev){ev.preventDefault();ev.stopPropagation();}observerFabDoubleLock=true;if(observerFabClickTimer){clearTimeout(observerFabClickTimer);observerFabClickTimer=null;}openObserverSettings();setTimeout(()=>{observerFabDoubleLock=false;},280);}
async function openObserverSettings(){if(!currentRoomID){notify('请先选择房间','error');return;}const room=rooms.find(r=>r.id===currentRoomID);const observer=getObserverAgent(room);if(!observer){notify('旁观者尚未就绪','error');return;}editingObserverID=observer.id;document.getElementById('observer-name').value=observer.name||'';document.getElementById('observer-personality').value=observer.personality||'';document.getElementById('observer-color').value=observer.avatar_color||'#7c3aed';populateProviderSelectForObserver();document.getElementById('observer-provider').value=observer.provider_id||'';openModal('modal-observer');}
function updateStatusBar(room){document.getElementById('status-msg-count').textContent=room?'消息数: '+(room.messages||[]).length+(room.max_messages?'/'+room.max_messages:''):'';}  
function connectWS(roomID){if(wsHandle){wsHandle.close();wsHandle=null;}const proto=location.protocol==='https:'?'wss':'ws';let ws=null;let reconnectTimer=null;let closed=false;function connect(){if(closed)return;ws=new WebSocket(proto+'://'+location.host+'/api/rooms/'+roomID+'/ws');ws.onopen=()=>{document.getElementById('status-ws').textContent='WS: 已连接';if(reconnectTimer){clearTimeout(reconnectTimer);reconnectTimer=null;}};ws.onclose=()=>{document.getElementById('status-ws').textContent='WS: 已断开';if(!closed&&roomID===currentRoomID){document.getElementById('status-ws').textContent='WS: 重连中...';reconnectTimer=setTimeout(connect,3000);}};ws.onerror=()=>{ws.close();};ws.onmessage=(e)=>{try{const parsed=JSON.parse(e.data);wsDebugLog('socket_in',parsed);handleWSEvent(parsed);}catch(err){if(wsDebugEnabled())console.warn('[WS-DEBUG] parse error',err,e.data);}};}connect();wsHandle={close:()=>{closed=true;if(reconnectTimer)clearTimeout(reconnectTimer);if(ws)ws.close();ws=null;}};}
function handleWSEvent(ev){wsDebugLog('before_handle',ev);if(ev.type==='room_update'){const room=ev.payload;if(room&&room.agents){const idx=rooms.findIndex(r=>r.id===room.id);if(idx>=0)rooms[idx]=room;else rooms.push(room);renderRoomList();if(room.id===currentRoomID){document.getElementById('room-title').textContent=room.name;const topicEl=document.getElementById('room-topic-display');topicEl.textContent=room.topic||'';if(room.stop_condition)topicEl.textContent+=' | 停止: '+room.stop_condition;renderAgents(room.agents||[],room);ensureDefaultObserver(room);updateStatusBar(room);}}}else if(ev.type==='message'){const msg=ev.payload;appendMessage(msg);const room=rooms.find(r=>r.id===currentRoomID);if(room){if(!room.messages)room.messages=[];room.messages.push(msg);}updateStatusBar(rooms.find(r=>r.id===currentRoomID));}else if(ev.type==='status'){const p=ev.payload;const room=rooms.find(r=>r.id===p.room_id);if(room)room.is_running=p.running;renderRoomList();const bs=document.getElementById('btn-start'),bp=document.getElementById('btn-stop'),br=document.getElementById('btn-restart');if(p.running){bs.style.display='none';bp.style.display='';if(br)br.style.display='none';showTyping(true);}else{bs.style.display='';bp.style.display='none';if(br)br.style.display='';showTyping(false);}}else if(ev.type==='thinking'){const p=ev.payload;showTyping(true,p.agent);}else if(ev.type==='error'){notify('AI 错误 ['+ev.payload.agent+']: '+ev.payload.error,'error');showTyping(false);}else if(ev.type==='stop_condition_met'){const room=rooms.find(r=>r.id===ev.payload.room_id);if(room)room.is_running=false;renderRoomList();document.getElementById('btn-start').style.display='';document.getElementById('btn-stop').style.display='none';const br=document.getElementById('btn-restart');if(br)br.style.display='';showTyping(false);notify('讨论已结束：停止条件已触发','success');}wsDebugLog('after_handle',ev);}
function showTyping(show,agentName){const el=document.getElementById('typing-indicator');el.style.display=show?'flex':'none';const txt=el.querySelector('.typing-agent-name');if(txt){txt.textContent=show&&agentName?agentName+' 正在思考...':'AI 正在思考...';}}
function toggleSysCmd(){const b=document.getElementById('syscmd-body');const ic=document.getElementById('syscmd-toggle-icon');b.classList.toggle('open');ic.textContent=b.classList.contains('open')?'▲':'▼';}
async function sendSysCmd(stopRoom){if(stopRoom===undefined)stopRoom=false;if(!currentRoomID){notify('请先选择房间','error');return;}const text=document.getElementById('syscmd-text').value.trim();if(!text&&!stopRoom){notify('请输入指令内容','error');return;}try{await apiFetch('/api/rooms/'+currentRoomID+'/syscmd',{method:'POST',body:JSON.stringify({text:text,stop_room:stopRoom})});document.getElementById('syscmd-text').value='';notify(stopRoom?'停止指令已发送':'指令已发送');}catch(e){notify('发送失败: '+e.message,'error');}}
function openCreateRoom(){editingRoomID=null;document.getElementById('modal-room-title').textContent='新建房间';['room-name','room-topic','room-rules','room-stop-condition'].forEach(id=>document.getElementById(id).value='');document.getElementById('room-maxmsg').value='0';populateRoomTemplateSelect();const s=document.getElementById('room-template-select');if(s)s.value='';openModal('modal-room');}
function openEditRoom(){const room=rooms.find(r=>r.id===currentRoomID);if(!room)return;editingRoomID=room.id;document.getElementById('modal-room-title').textContent='编辑房间';document.getElementById('room-name').value=room.name;document.getElementById('room-topic').value=room.topic||'';document.getElementById('room-rules').value=room.rules||'';document.getElementById('room-maxmsg').value=room.max_messages||0;document.getElementById('room-stop-condition').value=room.stop_condition||'';populateRoomTemplateSelect();openModal('modal-room');}
async function saveRoom(){const body={name:document.getElementById('room-name').value.trim(),topic:document.getElementById('room-topic').value.trim(),rules:document.getElementById('room-rules').value.trim(),max_messages:parseInt(document.getElementById('room-maxmsg').value)||0,stop_condition:document.getElementById('room-stop-condition').value.trim()};if(!body.name){notify('请输入房间名称','error');return;}try{if(editingRoomID){await apiFetch('/api/rooms/'+editingRoomID,{method:'PUT',body:JSON.stringify(body)});notify('房间已更新');}else{const room=await apiFetch('/api/rooms',{method:'POST',body:JSON.stringify(body)});rooms.push(room);await selectRoom(room.id);notify('房间已创建');}closeModal('modal-room');await loadRooms();}catch(e){notify('操作失败: '+e.message,'error');}}
async function deleteRoom(){if(!currentRoomID)return;showConfirm('确定删除该房间？',async()=>{try{await apiFetch('/api/rooms/'+currentRoomID,{method:'DELETE'});rooms=rooms.filter(r=>r.id!==currentRoomID);currentRoomID=null;if(wsHandle){wsHandle.close();wsHandle=null;}document.getElementById('no-room-view').style.display='';document.getElementById('room-view').style.display='none';renderRoomList();notify('房间已删除');}catch(e){notify('删除失败: '+e.message,'error');}});}
async function startRoom(){if(!currentRoomID)return;try{await apiFetch('/api/rooms/'+currentRoomID+'/start',{method:'POST'});notify('聊天室已启动');}catch(e){notify('启动失败: '+e.message,'error');}}
async function stopRoom(){if(!currentRoomID)return;try{await apiFetch('/api/rooms/'+currentRoomID+'/stop',{method:'POST'});notify('聊天室已停止');}catch(e){notify('停止失败: '+e.message,'error');}}
async function restartRoom(){if(!currentRoomID)return;if(!confirm('重新开始将清空所有消息，确定？'))return;try{await apiFetch('/api/rooms/'+currentRoomID+'/restart',{method:'POST'});notify('房间已重新开始');const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('重开失败: '+e.message,'error');}}
async function cloneRoom(id){try{const r=await apiFetch('/api/rooms/'+id+'/clone',{method:'POST'});rooms.push(r);renderRoomList();notify('房间已复制');}catch(e){notify('复制失败: '+e.message,'error');}}
async function exportRoom(id,fmt){try{const r=await fetch('/api/rooms/'+id+'/export?format='+fmt);const text=await r.text();const blob=new Blob([text],{type:fmt==='json'?'application/json':'text/markdown'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='room-'+id+'.'+fmt;a.click();}catch(e){notify('导出失败','error');}}
function openAddAgent(){if(!currentRoomID){notify('请先选择房间','error');return;}editingAgentID=null;document.getElementById('agent-name').value='';document.getElementById('agent-personality').value='';document.getElementById('agent-is-assistant').checked=false;document.getElementById('agent-color').value='#0ea5e9';document.getElementById('agent-avatar-preview').style.display='none';document.getElementById('agent-avatar-file').value='';populateProviderSelect();populateAgentPersonaFolders();populatePersonaSelect();openModal('modal-agent');}
function openAddObserver(){if(!currentRoomID){notify('请先选择房间','error');return;}editingObserverID=null;document.getElementById('observer-name').value='';document.getElementById('observer-personality').value='请保持中立，重点提炼讨论脉络与分歧点。';document.getElementById('observer-color').value='#7c3aed';populateProviderSelectForObserver();openModal('modal-observer');}
function populateProviderSelect(){const sel=document.getElementById('agent-provider');sel.innerHTML=providers.length?providers.map(p=>`<option value="${p.id}">${escHtml(p.name)} (${escHtml(p.model)})</option>`).join(''):'<option value="">-- 请先添加提供商 --</option>';}function populateProviderSelectForObserver(){const sel=document.getElementById('observer-provider');if(!sel)return;sel.innerHTML=providers.length?providers.map(p=>`<option value="${p.id}">${escHtml(p.name)} (${escHtml(p.model)})</option>`).join(''):'<option value="">-- 请先添加提供商 --</option>';}
function populateAgentPersonaFolders(){const sel=document.getElementById('agent-persona-folder');if(!sel)return;sel.innerHTML='<option value="">-- 全部文件夹 --</option>'+folders.map(f=>`<option value="${f.id}">${escHtml(f.name)}</option>`).join('');sel.value='';}
function onAgentPersonaFolderChange(folderID){populatePersonaSelect(folderID||'');}
function populatePersonaSelect(folderID=''){const sel=document.getElementById('agent-persona-select');let list=personas; if(folderID) list=personas.filter(p=>p.folder_id===folderID);sel.innerHTML='<option value="">-- 自定义 --</option>'+list.map(p=>`<option value="${p.id}">${escHtml(p.name)}</option>`).join('');}
function onPersonaSelect(pid){if(!pid)return;const p=personas.find(x=>x.id===pid);if(!p)return;document.getElementById('agent-name').value=p.name;document.getElementById('agent-personality').value=p.personality||'';document.getElementById('agent-color').value=p.avatar_color||'#0ea5e9';if(p.avatar_image){const img=document.getElementById('agent-avatar-preview');img.src=p.avatar_image;img.style.display='block';}}
function previewAgentAvatar(input){if(!input.files||!input.files[0])return;const reader=new FileReader();reader.onload=e=>{const img=document.getElementById('agent-avatar-preview');img.src=e.target.result;img.style.display='block';};reader.readAsDataURL(input.files[0]);}
async function saveAgent(){const name=document.getElementById('agent-name').value.trim();const providerID=document.getElementById('agent-provider').value;const personality=document.getElementById('agent-personality').value.trim();const isAssistant=document.getElementById('agent-is-assistant').checked;const color=document.getElementById('agent-color').value;const avatarImg=document.getElementById('agent-avatar-preview');const avatarImage=avatarImg.style.display!=='none'?avatarImg.src:'';if(!name){notify('请输入角色名称','error');return;}if(!providerID){notify('请选择模型提供商','error');return;}try{if(editingAgentID){await apiFetch('/api/rooms/'+currentRoomID+'/agents/'+editingAgentID,{method:'DELETE'});}const agent=await apiFetch('/api/rooms/'+currentRoomID+'/agents',{method:'POST',body:JSON.stringify({name,provider_id:providerID,personality,avatar_color:color,avatar_image:avatarImage,is_assistant:isAssistant})});closeModal('modal-agent');editingAgentID=null;notify('AI 角色已保存');agentColorCache[agent.id]=color;const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('操作失败: '+e.message,'error');}}
async function saveObserver(){const name=document.getElementById('observer-name').value.trim();const providerID=document.getElementById('observer-provider').value;const personality=document.getElementById('observer-personality').value.trim();const color=document.getElementById('observer-color').value;if(!name){notify('请输入旁观者名称','error');return;}if(!providerID){notify('请选择模型提供商','error');return;}try{if(editingObserverID){await apiFetch('/api/rooms/'+currentRoomID+'/agents/'+editingObserverID,{method:'DELETE'});}await apiFetch('/api/rooms/'+currentRoomID+'/agents',{method:'POST',body:JSON.stringify({name,provider_id:providerID,personality,avatar_color:color,is_observer:true})});closeModal('modal-observer');editingObserverID=null;notify('旁观者已保存');const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('操作失败: '+e.message,'error');}}
async function removeAgent(roomID,agentID){showConfirm('确定移除该 AI 角色？',async()=>{try{await apiFetch('/api/rooms/'+roomID+'/agents/'+agentID,{method:'DELETE'});notify('已移除');const fullRoom=await apiFetch('/api/rooms/'+roomID);const idx=rooms.findIndex(r=>r.id===roomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('移除失败: '+e.message,'error');}});} 
function closeAgentContextMenu(){const m=document.getElementById('agent-context-menu');if(m)m.style.display='none';activeAgentContext=null;}
function openAgentContextMenu(ev,roomID,agentID,roleType){ev.preventDefault();ev.stopPropagation();const menu=document.getElementById('agent-context-menu');if(!menu)return;activeAgentContext={roomID,agentID,roleType};const chatBtn=document.getElementById('ctx-observer-chat');if(chatBtn)chatBtn.style.display='none';const refereeBtn=document.getElementById('ctx-referee-manage');if(refereeBtn)refereeBtn.style.display=roleType==='referee'?'':'none';menu.style.left=`${ev.pageX}px`;menu.style.top=`${ev.pageY}px`;menu.style.display='block';}
function openAgentContextMenuByDouble(roomID,agentID,roleType,ev,el){if(!ev)return;ev.preventDefault();ev.stopPropagation();contextMenuHoldUntil=Date.now()+500;const menu=document.getElementById('agent-context-menu');if(!menu)return;activeAgentContext={roomID,agentID,roleType};const refereeBtn=document.getElementById('ctx-referee-manage');if(refereeBtn)refereeBtn.style.display=roleType==='referee'?'':'none';const rect=el&&el.getBoundingClientRect?el.getBoundingClientRect():null;const x=rect?rect.right+8:ev.pageX;const y=rect?(rect.top+window.scrollY+6):ev.pageY;menu.style.left=`${x}px`;menu.style.top=`${y}px`;menu.style.display='block';}
function handleAgentCardDoubleClick(ev){const card=ev.target&&ev.target.closest?ev.target.closest('.agent-card'):null;if(!card)return;const roomID=card.getAttribute('data-room-id');const agentID=card.getAttribute('data-agent-id');const roleType=card.getAttribute('data-role-type')||'normal';if(!roomID||!agentID)return;openAgentContextMenuByDouble(roomID,agentID,roleType,ev,card);}
async function contextEditAgent(){if(!activeAgentContext)return;const {roomID,agentID,roleType}=activeAgentContext;closeAgentContextMenu();const room=await apiFetch('/api/rooms/'+roomID);const agent=(room.agents||[]).find(a=>a.id===agentID);if(!agent)return;editingAgentID=agentID;document.getElementById('agent-name').value=agent.name||'';document.getElementById('agent-personality').value=agent.personality||'';document.getElementById('agent-is-assistant').checked=!!agent.is_assistant;document.getElementById('agent-color').value=agent.avatar_color||'#0ea5e9';populateProviderSelect();populateAgentPersonaFolders();populatePersonaSelect();document.getElementById('agent-provider').value=agent.provider_id||'';openModal('modal-agent');}
function openObserverChatByContext(){openObserverChat();}
function openObserverChatByCard(roomID,observerID){observerChatState={roomID,observerID};const fab=document.getElementById('observer-fab');if(fab)fab.style.display='none';const win=document.getElementById('observer-chat-float');if(win){win.style.display='flex';}document.getElementById('observer-chat-log').innerHTML='';document.getElementById('observer-chat-input').value='';}
function closeObserverChatWindow(){const win=document.getElementById('observer-chat-float');if(win)win.style.display='none';const room=rooms.find(r=>r.id===currentRoomID);const observer=getObserverAgent(room);const fab=document.getElementById('observer-fab');if(fab&&observer)fab.style.display='flex';}
function startObserverWindowDrag(ev){const win=document.getElementById('observer-chat-float');if(!win)return;observerDragState.dragging=true;observerDragState.offsetX=ev.clientX-win.offsetLeft;observerDragState.offsetY=ev.clientY-win.offsetTop;ev.preventDefault();}
function startPanelResize(ev,target,minWidth,maxWidth){if(!target)return;panelResizeState.target=target;panelResizeState.startX=ev.clientX;panelResizeState.startWidth=target.offsetWidth;panelResizeState.minWidth=minWidth;panelResizeState.maxWidth=maxWidth;ev.preventDefault();}
function onPanelResize(ev){if(!panelResizeState.target)return;const t=panelResizeState.target;const isAgents=t.id==='agents-panel';const dx=ev.clientX-panelResizeState.startX;let width=isAgents?(panelResizeState.startWidth-dx):(panelResizeState.startWidth+dx);width=Math.max(panelResizeState.minWidth,Math.min(panelResizeState.maxWidth,width));t.style.width=width+'px';}
function endPanelResize(){panelResizeState.target=null;}
function onObserverWindowDrag(ev){if(!observerDragState.dragging)return;const win=document.getElementById('observer-chat-float');if(!win)return;const maxX=Math.max(0,window.innerWidth-win.offsetWidth);const maxY=Math.max(0,window.innerHeight-win.offsetHeight);const x=Math.min(maxX,Math.max(0,ev.clientX-observerDragState.offsetX));const y=Math.min(maxY,Math.max(0,ev.clientY-observerDragState.offsetY));win.style.left=x+'px';win.style.top=y+'px';win.style.right='auto';win.style.bottom='auto';}
function endObserverWindowDrag(){observerDragState.dragging=false;}
function contextManageReferee(){closeAgentContextMenu();openRefereeModal();}
async function sendObserverChat(){const text=document.getElementById('observer-chat-input').value.trim();if(!text||!observerChatState.roomID||!observerChatState.observerID)return;const log=document.getElementById('observer-chat-log');log.innerHTML+=`<div class="observer-line user">${escHtml(text)}</div>`;document.getElementById('observer-chat-input').value='';const thinkingId='thinking-'+Date.now();log.innerHTML+=`<div class="observer-line bot thinking" data-thinking-id="${thinkingId}">正在思考...</div>`;log.scrollTop=log.scrollHeight;try{const msg=await apiFetch('/api/rooms/'+observerChatState.roomID+'/observer-chat',{method:'POST',body:JSON.stringify({observer_id:observerChatState.observerID,text})});const thinkingEl=log.querySelector(`[data-thinking-id="${thinkingId}"]`);if(thinkingEl)thinkingEl.remove();log.innerHTML+=`<div class="observer-line bot">${escHtml(msg.content||'')}</div>`;log.scrollTop=log.scrollHeight;}catch(e){const thinkingEl=log.querySelector(`[data-thinking-id="${thinkingId}"]`);if(thinkingEl)thinkingEl.remove();log.innerHTML+=`<div class="observer-line err">错误：${escHtml(e.message||'请求失败')}</div>`;}}

function openRefereeModal(){if(!currentRoomID){notify('请先选择房间','error');return;}const room=rooms.find(r=>r.id===currentRoomID);const referee=room&&room.agents?room.agents.find(a=>a.is_referee):null;document.getElementById('modal-referee-title').textContent=referee?'编辑裁判':'设置 AI 裁判';document.getElementById('referee-remove-btn').style.display=referee?'':'none';document.getElementById('referee-id').value=referee?referee.id:'';document.getElementById('referee-name').value=referee?referee.name:'';document.getElementById('referee-personality').value=referee?referee.personality||'':'';document.getElementById('referee-color').value=referee?referee.avatar_color||'#7c3aed':'#7c3aed';const rpSel=document.getElementById('referee-persona-select');rpSel.innerHTML='<option value="">-- 自定义 --</option>'+personas.filter(p=>p.is_referee).map(p=>`<option value="${p.id}">${escHtml(p.name)}</option>`).join('');rpSel.value='';const sel=document.getElementById('referee-provider');sel.innerHTML=providers.map(p=>`<option value="${p.id}">${escHtml(p.name)} (${escHtml(p.model)})</option>`).join('');if(referee&&referee.provider_id)sel.value=referee.provider_id;openModal('modal-referee');}
function onRefereePersonaSelect(pid){if(!pid)return;const p=personas.find(x=>x.id===pid);if(!p)return;document.getElementById('referee-name').value=p.name;document.getElementById('referee-personality').value=p.personality||'';document.getElementById('referee-color').value=p.avatar_color||'#7c3aed';}
async function saveReferee(){const name=document.getElementById('referee-name').value.trim();const providerID=document.getElementById('referee-provider').value;const personality=document.getElementById('referee-personality').value.trim();const color=document.getElementById('referee-color').value;const existingID=document.getElementById('referee-id').value;if(!name){notify('请输入裁判名称','error');return;}if(!providerID){notify('请选择模型提供商','error');return;}try{if(existingID)await apiFetch('/api/rooms/'+currentRoomID+'/agents/'+existingID,{method:'DELETE'});await apiFetch('/api/rooms/'+currentRoomID+'/agents',{method:'POST',body:JSON.stringify({name,provider_id:providerID,personality,avatar_color:color,is_referee:true})});closeModal('modal-referee');notify('AI 裁判已设置');const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('操作失败: '+e.message,'error');}}
async function removeReferee(){const id=document.getElementById('referee-id').value;if(!id)return;showConfirm('确定移除 AI 裁判？',async()=>{try{await apiFetch('/api/rooms/'+currentRoomID+'/agents/'+id,{method:'DELETE'});closeModal('modal-referee');notify('裁判已移除');const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('移除失败: '+e.message,'error');}});}
async function loadProviders(){try{providers=await apiFetch('/api/providers')||[];renderProvidersGrid();}catch(e){notify('加载提供商失败','error');}}
function renderProvidersGrid(){const grid=document.getElementById('providers-grid');if(!providers.length){grid.innerHTML='<div style="color:var(--text-muted);font-size:13px;padding:20px">暂无提供商，点击添加提供商</div>';return;}grid.innerHTML=providers.map(p=>`<div class="provider-card"><div class="provider-card-top"><div class="provider-name">${escHtml(p.name)}</div><div class="provider-model">${escHtml(p.model)}</div></div><div class="provider-url">${escHtml(p.base_url)}</div><div class="provider-actions"><button class="btn btn-ghost btn-sm" onclick="editProvider('${p.id}')">编辑</button><button class="btn btn-primary btn-sm" onclick="testProvider('${p.id}')">测试</button><button class="btn btn-danger btn-sm" onclick="delProvider('${p.id}')">删除</button></div></div>`).join('');}
function openAddProvider(){editingProviderID=null;document.getElementById('modal-provider-title').textContent='添加提供商';['prov-name','prov-url','prov-key','prov-model'].forEach(id=>document.getElementById(id).value='');document.getElementById('prov-tokens').value='500';openModal('modal-provider');}
function editProvider(id){const p=providers.find(x=>x.id===id);if(!p)return;editingProviderID=id;document.getElementById('modal-provider-title').textContent='编辑提供商';document.getElementById('prov-name').value=p.name;document.getElementById('prov-url').value=p.base_url;document.getElementById('prov-key').value=p.api_key||'';document.getElementById('prov-model').value=p.model;document.getElementById('prov-tokens').value=p.max_tokens||500;openModal('modal-provider');}
async function saveProvider(){const body={name:document.getElementById('prov-name').value.trim(),base_url:document.getElementById('prov-url').value.trim(),api_key:document.getElementById('prov-key').value.trim(),model:document.getElementById('prov-model').value.trim(),max_tokens:parseInt(document.getElementById('prov-tokens').value)||500};if(!body.name||!body.base_url||!body.model){notify('名称、URL 和模型为必填项','error');return;}try{if(editingProviderID){await apiFetch('/api/providers/'+editingProviderID,{method:'PUT',body:JSON.stringify(body)});notify('提供商已更新');}else{await apiFetch('/api/providers',{method:'POST',body:JSON.stringify(body)});notify('提供商已添加');}closeModal('modal-provider');await loadProviders();}catch(e){notify('操作失败: '+e.message,'error');}}
async function delProvider(id){if(!confirm('确定删除该提供商？'))return;try{await apiFetch('/api/providers/'+id,{method:'DELETE'});notify('已删除');await loadProviders();}catch(e){notify('删除失败','error');}}
async function testProvider(id){const p=providers.find(x=>x.id===id);if(!p){notify('找不到提供商','error');return;}const logEl=document.getElementById('test-log');const modal=document.getElementById('modal-test');document.getElementById('test-provider-name').textContent=p.name+' ('+p.model+')';logEl.textContent='';modal.classList.add('open');const log=(msg,cls='')=>{const line=document.createElement('div');line.className='test-log-line'+(cls?' '+cls:'');line.textContent=msg;logEl.appendChild(line);logEl.scrollTop=logEl.scrollHeight;};log('开始测试: '+new Date().toLocaleTimeString());log('提供商: '+p.name);log('Base URL: '+p.base_url);log('模型: '+p.model);log('Max Tokens: '+p.max_tokens);log('─────────────────────────────');const t0=Date.now();try{log('正在发送测试请求...');const payload={model:p.model,messages:[{role:'user',content:'请用一句话介绍你自己。'}],max_tokens:60,stream:false};log('请求体: '+JSON.stringify(payload,null,2));const resp=await fetch(p.base_url.replace(/\/+$/,'')+'/chat/completions',{method:'POST',headers:{'Content-Type':'application/json',...(p.api_key?{'Authorization':'Bearer '+p.api_key}:{})},body:JSON.stringify(payload)});const elapsed=Date.now()-t0;log('HTTP 状态: '+resp.status+' '+resp.statusText+' ('+elapsed+'ms)');const text=await resp.text();log('原始响应:');log(text);try{const json=JSON.parse(text);if(json.error){log('API 错误: '+json.error.message,'log-error');}else if(json.choices&&json.choices[0]){log('─────────────────────────────');log('✓ 测试成功！','log-ok');log('回复内容: '+json.choices[0].message.content);log('Token 用量: '+(json.usage?JSON.stringify(json.usage):'N/A'));}}catch(e){log('JSON 解析失败: '+e.message,'log-error');}}catch(e){const elapsed=Date.now()-t0;log('请求失败 ('+elapsed+'ms): '+e.message,'log-error');}}
async function loadPersonas(){try{personas=await apiFetch('/api/personas')||[];}catch(e){}}
async function loadFolders(){try{folders=await apiFetch('/api/folders')||[];}catch(e){}}
async function loadPersonasPage(){await loadPersonas();await loadFolders();renderFolderList();renderPersonasGrid();}
function renderFolderList(){const list=document.getElementById('folder-list');list.innerHTML='<div class="folder-item '+(currentFolderFilter===null?'active':'')+'" onclick="filterByFolder(null)"><span class="folder-item-name">全部角色</span></div>'+folders.map(f=>`<div class="folder-item ${currentFolderFilter===f.id?'active':''}" onclick="filterByFolder('${f.id}')"><span class="folder-item-name">${escHtml(f.name)}</span><div class="folder-actions"><button class="folder-edit" onclick="event.stopPropagation();renameFolder('${f.id}','${escHtml(f.name)}')">✎</button><button class="folder-del" onclick="event.stopPropagation();delFolder('${f.id}')">&#x2715;</button></div></div>`).join('');}
function filterByFolder(id){currentFolderFilter=id;renderFolderList();renderPersonasGrid();}
function renderPersonasGrid(){const grid=document.getElementById('personas-grid');let list=personas;if(currentFolderFilter)list=personas.filter(p=>p.folder_id===currentFolderFilter);if(!list.length){grid.innerHTML='<div style="color:var(--text-muted);font-size:13px;padding:20px">暂无角色，点击新建角色</div>';return;}grid.innerHTML=list.map(p=>{const folder=folders.find(f=>f.id===p.folder_id);const tags=(p.tags||[]).map(t=>`<span class="persona-tag">${escHtml(t)}</span>`).join('');const av=p.avatar_image?`<img src="${p.avatar_image}" />`:(p.name||'?').slice(0,2).toUpperCase();const refBadge=p.is_referee?'<span class="referee-badge">裁判</span>':'';return `<div class="persona-card"><div class="persona-card-top"><div class="persona-big-avatar" style="background:${p.avatar_color||'#0ea5e9'}">${av}</div><div class="persona-card-meta"><div class="persona-card-name">${escHtml(p.name)}${refBadge}</div><div class="persona-card-folder">${folder?escHtml(folder.name):''}</div></div></div><div class="persona-card-tags">${tags}</div><div class="persona-card-desc">${escHtml(p.personality||'')}</div><div class="persona-card-actions"><button class="btn btn-ghost btn-sm" onclick="editPersona('${p.id}')">编辑</button><button class="btn btn-danger btn-sm" onclick="delPersona('${p.id}')">删除</button></div></div>`;}).join('');}
function populateFolderSelect(selectedID){const sel=document.getElementById('persona-folder');sel.innerHTML='<option value="">无文件夹</option>'+folders.map(f=>`<option value="${f.id}" ${f.id===selectedID?'selected':''}>${escHtml(f.name)}</option>`).join('');}
function openCreatePersona(){editingPersonaID=null;document.getElementById('modal-persona-title').textContent='新建 AI 角色';['persona-name','persona-tags'].forEach(id=>document.getElementById(id).value='');document.getElementById('persona-personality').value='';document.getElementById('persona-color').value='#0ea5e9';document.getElementById('persona-avatar-preview').style.display='none';document.getElementById('persona-avatar-data').value='';document.getElementById('persona-video-data').value='';document.getElementById('persona-video-name').textContent='';document.getElementById('persona-is-referee').checked=false;document.getElementById('persona-id').value='';populateFolderSelect();openModal('modal-persona');}
function editPersona(id){const p=personas.find(x=>x.id===id);if(!p)return;editingPersonaID=id;document.getElementById('modal-persona-title').textContent='编辑 AI 角色';document.getElementById('persona-name').value=p.name;document.getElementById('persona-personality').value=p.personality||'';document.getElementById('persona-color').value=p.avatar_color||'#0ea5e9';document.getElementById('persona-tags').value=(p.tags||[]).join(',');document.getElementById('persona-id').value=p.id;document.getElementById('persona-avatar-data').value=p.avatar_image||'';document.getElementById('persona-video-data').value=p.video_url||'';if(p.avatar_image){const img=document.getElementById('persona-avatar-preview');img.src=p.avatar_image;img.style.display='block';}else{document.getElementById('persona-avatar-preview').style.display='none';}document.getElementById('persona-video-name').textContent=p.video_url?'已上传视频':'';document.getElementById('persona-is-referee').checked=p.is_referee||false;populateFolderSelect(p.folder_id);openModal('modal-persona');}
async function savePersona(){const name=document.getElementById('persona-name').value.trim();if(!name){notify('请输入角色名称','error');return;}const tagsRaw=document.getElementById('persona-tags').value.trim();const body={name,personality:document.getElementById('persona-personality').value.trim(),avatar_color:document.getElementById('persona-color').value,folder_id:document.getElementById('persona-folder').value||'',tags:tagsRaw?tagsRaw.split(',').map(t=>t.trim()).filter(Boolean):[],avatar_image:document.getElementById('persona-avatar-data').value,video_url:document.getElementById('persona-video-data').value,is_referee:document.getElementById('persona-is-referee').checked};const existingID=document.getElementById('persona-id').value;try{if(existingID){await apiFetch('/api/personas/'+existingID,{method:'PUT',body:JSON.stringify(body)});notify('角色已更新');}else{await apiFetch('/api/personas',{method:'POST',body:JSON.stringify(body)});notify('角色已创建');}closeModal('modal-persona');await loadPersonasPage();}catch(e){notify('操作失败: '+e.message,'error');}}
async function delPersona(id){if(!confirm('确定删除该角色？'))return;try{await apiFetch('/api/personas/'+id,{method:'DELETE'});notify('已删除');await loadPersonasPage();}catch(e){notify('删除失败','error');}}
function previewPersonaAvatar(input){if(!input.files||!input.files[0])return;const reader=new FileReader();reader.onload=e=>{document.getElementById('persona-avatar-data').value=e.target.result;const img=document.getElementById('persona-avatar-preview');img.src=e.target.result;img.style.display='block';};reader.readAsDataURL(input.files[0]);}
function previewPersonaVideo(input){if(!input.files||!input.files[0])return;const reader=new FileReader();reader.onload=e=>{document.getElementById('persona-video-data').value=e.target.result;document.getElementById('persona-video-name').textContent=input.files[0].name;};reader.readAsDataURL(input.files[0]);}
function openCreateFolder(){const name=prompt('请输入文件夹名称');if(!name||!name.trim())return;apiFetch('/api/folders',{method:'POST',body:JSON.stringify({name:name.trim()})}).then(()=>loadPersonasPage()).then(()=>notify('文件夹已创建')).catch(()=>notify('创建失败','error'));}
async function saveFolder(){const name=document.getElementById('folder-name').value.trim();if(!name){notify('请输入文件夹名称','error');return;}try{await apiFetch('/api/folders',{method:'POST',body:JSON.stringify({name})});closeModal('modal-folder');await loadPersonasPage();}catch(e){notify('创建失败','error');}}
async function delFolder(id){if(!confirm('确定删除文件夹？文件夹内角色不会被删除。'))return;try{await apiFetch('/api/folders/'+id,{method:'DELETE'});await loadPersonasPage();}catch(e){notify('删除失败','error');}}
async function renameFolder(id,currentName){const name=prompt('修改文件夹名称',currentName||'');if(!name||!name.trim())return;try{await apiFetch('/api/folders/'+id,{method:'PUT',body:JSON.stringify({name:name.trim()})});notify('文件夹已重命名');await loadPersonasPage();}catch(e){notify('重命名失败: '+e.message,'error');}}
async function loadTemplates(){try{templates=await apiFetch('/api/templates')||[];renderTemplatesGrid();}catch(e){}}
function renderTemplatesGrid(){const grid=document.getElementById('templates-grid');if(!grid)return;if(!templates.length){grid.innerHTML='<div style="color:var(--text-muted);font-size:13px;padding:20px">暂无模板，点击新建模板</div>';return;}grid.innerHTML=templates.map(t=>{const tags=(t.tags||[]).map(tag=>`<span class="template-meta-tag">${escHtml(tag)}</span>`).join('');const meta=[t.max_messages?'最多'+t.max_messages+'条':''].filter(Boolean).map(m=>`<span class="template-meta-tag">${m}</span>`).join('');return `<div class="template-card"><div class="template-card-name">${escHtml(t.name)}</div>${t.description?`<div class="template-card-desc">${escHtml(t.description)}</div>`:''}<div class="template-card-meta">${tags}${meta}</div><div class="template-card-actions"><button class="btn btn-primary btn-sm" onclick="useTemplate('${t.id}')">使用</button><button class="btn btn-ghost btn-sm" onclick="editTemplate('${t.id}')">编辑</button><button class="btn btn-danger btn-sm" onclick="delTemplate('${t.id}')">删除</button></div></div>`;}).join('');}
function populateRoomTemplateSelect(){const sel=document.getElementById('room-template-select');if(!sel)return;sel.innerHTML='<option value="">-- 不使用 --</option>'+templates.map(t=>`<option value="${t.id}">${escHtml(t.name)}</option>`).join('');}
function applyRoomTemplate(id){if(!id)return;const t=templates.find(x=>x.id===id);if(!t)return;if(t.topic)document.getElementById('room-topic').value=t.topic;if(t.rules)document.getElementById('room-rules').value=t.rules;if(t.stop_condition)document.getElementById('room-stop-condition').value=t.stop_condition;if(t.max_messages!=null)document.getElementById('room-maxmsg').value=t.max_messages;}
function useTemplate(id){showPage('chat');openCreateRoom();setTimeout(()=>{const sel=document.getElementById('room-template-select');if(sel){sel.value=id;applyRoomTemplate(id);}},80);}
function openCreateTemplate(){document.getElementById('modal-template-title').textContent='新建模板';['tpl-name','tpl-desc','tpl-topic','tpl-rules','tpl-stop-condition','tpl-tags'].forEach(id=>document.getElementById(id).value='');document.getElementById('tpl-maxmsg').value='0';document.getElementById('tpl-id').value='';openModal('modal-template');}
function editTemplate(id){const t=templates.find(x=>x.id===id);if(!t)return;document.getElementById('modal-template-title').textContent='编辑模板';document.getElementById('tpl-name').value=t.name;document.getElementById('tpl-desc').value=t.description||'';document.getElementById('tpl-topic').value=t.topic||'';document.getElementById('tpl-rules').value=t.rules||'';document.getElementById('tpl-stop-condition').value=t.stop_condition||'';document.getElementById('tpl-maxmsg').value=t.max_messages||0;document.getElementById('tpl-tags').value=(t.tags||[]).join(',');document.getElementById('tpl-id').value=t.id;openModal('modal-template');}
async function saveTemplate(){const name=document.getElementById('tpl-name').value.trim();if(!name){notify('请输入模板名称','error');return;}const tagsRaw=document.getElementById('tpl-tags').value.trim();const body={name,description:document.getElementById('tpl-desc').value.trim(),topic:document.getElementById('tpl-topic').value.trim(),rules:document.getElementById('tpl-rules').value.trim(),stop_condition:document.getElementById('tpl-stop-condition').value.trim(),max_messages:parseInt(document.getElementById('tpl-maxmsg').value)||0,tags:tagsRaw?tagsRaw.split(',').map(t=>t.trim()).filter(Boolean):[]};const existingID=document.getElementById('tpl-id').value;try{if(existingID){await apiFetch('/api/templates/'+existingID,{method:'PUT',body:JSON.stringify(body)});notify('模板已更新');}else{await apiFetch('/api/templates',{method:'POST',body:JSON.stringify(body)});notify('模板已创建');}closeModal('modal-template');await loadTemplates();}catch(e){notify('操作失败: '+e.message,'error');}}
async function delTemplate(id){if(!confirm('确定删除该模板？'))return;try{await apiFetch('/api/templates/'+id,{method:'DELETE'});notify('已删除');await loadTemplates();}catch(e){notify('删除失败','error');}}
function openCreateRoom(){editingRoomID=null;document.getElementById('modal-room-title').textContent='新建房间';['room-name','room-topic','room-rules','room-stop-condition'].forEach(id=>document.getElementById(id).value='');document.getElementById('room-maxmsg').value='0';populateRoomTemplateSelect();const s=document.getElementById('room-template-select');if(s)s.value='';openModal('modal-room');}
function openEditRoom(){const room=rooms.find(r=>r.id===currentRoomID);if(!room)return;editingRoomID=room.id;document.getElementById('modal-room-title').textContent='编辑房间';document.getElementById('room-name').value=room.name;document.getElementById('room-topic').value=room.topic||'';document.getElementById('room-rules').value=room.rules||'';document.getElementById('room-maxmsg').value=room.max_messages||0;document.getElementById('room-stop-condition').value=room.stop_condition||'';populateRoomTemplateSelect();openModal('modal-room');}
async function saveRoom(){const body={name:document.getElementById('room-name').value.trim(),topic:document.getElementById('room-topic').value.trim(),rules:document.getElementById('room-rules').value.trim(),max_messages:parseInt(document.getElementById('room-maxmsg').value)||0,stop_condition:document.getElementById('room-stop-condition').value.trim()};if(!body.name){notify('请输入房间名称','error');return;}try{if(editingRoomID){await apiFetch('/api/rooms/'+editingRoomID,{method:'PUT',body:JSON.stringify(body)});notify('房间已更新');}else{const room=await apiFetch('/api/rooms',{method:'POST',body:JSON.stringify(body)});rooms.push(room);await selectRoom(room.id);notify('房间已创建');}closeModal('modal-room');await loadRooms();}catch(e){notify('操作失败: '+e.message,'error');}}
async function deleteRoom(){if(!currentRoomID)return;showConfirm('确定删除该房间？',async()=>{try{await apiFetch('/api/rooms/'+currentRoomID,{method:'DELETE'});rooms=rooms.filter(r=>r.id!==currentRoomID);currentRoomID=null;if(wsHandle){wsHandle.close();wsHandle=null;}document.getElementById('no-room-view').style.display='';document.getElementById('room-view').style.display='none';renderRoomList();notify('房间已删除');}catch(e){notify('删除失败: '+e.message,'error');}});}
async function startRoom(){if(!currentRoomID)return;try{await apiFetch('/api/rooms/'+currentRoomID+'/start',{method:'POST'});notify('聊天室已启动');}catch(e){notify('启动失败: '+e.message,'error');}}
async function stopRoom(){if(!currentRoomID)return;try{await apiFetch('/api/rooms/'+currentRoomID+'/stop',{method:'POST'});notify('聊天室已停止');}catch(e){notify('停止失败: '+e.message,'error');}}
async function restartRoom(){if(!currentRoomID)return;if(!confirm('重新开始将清空所有消息，确定？'))return;try{await apiFetch('/api/rooms/'+currentRoomID+'/restart',{method:'POST'});notify('房间已重新开始');const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('重开失败: '+e.message,'error');}}
async function cloneRoom(id){try{const r=await apiFetch('/api/rooms/'+id+'/clone',{method:'POST'});rooms.push(r);renderRoomList();notify('房间已复制');}catch(e){notify('复制失败: '+e.message,'error');}}
async function exportRoom(id,fmt){try{const r=await fetch('/api/rooms/'+id+'/export?format='+fmt);const text=await r.text();const blob=new Blob([text],{type:fmt==='json'?'application/json':'text/markdown'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='room-'+id+'.'+fmt;a.click();}catch(e){notify('导出失败','error');}}
function openAddAgent(){if(!currentRoomID){notify('请先选择房间','error');return;}editingAgentID=null;document.getElementById('agent-name').value='';document.getElementById('agent-personality').value='';document.getElementById('agent-is-assistant').checked=false;document.getElementById('agent-color').value='#0ea5e9';document.getElementById('agent-avatar-preview').style.display='none';document.getElementById('agent-avatar-file').value='';populateProviderSelect();populateAgentPersonaFolders();populatePersonaSelect();openModal('modal-agent');}
function openAddObserver(){if(!currentRoomID){notify('请先选择房间','error');return;}editingObserverID=null;document.getElementById('observer-name').value='';document.getElementById('observer-personality').value='请保持中立，重点提炼讨论脉络与分歧点。';document.getElementById('observer-color').value='#7c3aed';populateProviderSelectForObserver();openModal('modal-observer');}
function populateProviderSelect(){const sel=document.getElementById('agent-provider');sel.innerHTML=providers.length?providers.map(p=>`<option value="${p.id}">${escHtml(p.name)} (${escHtml(p.model)})</option>`).join(''):'<option value="">-- 请先添加提供商 --</option>';}function populateProviderSelectForObserver(){const sel=document.getElementById('observer-provider');if(!sel)return;sel.innerHTML=providers.length?providers.map(p=>`<option value="${p.id}">${escHtml(p.name)} (${escHtml(p.model)})</option>`).join(''):'<option value="">-- 请先添加提供商 --</option>';}
function populateAgentPersonaFolders(){const sel=document.getElementById('agent-persona-folder');if(!sel)return;sel.innerHTML='<option value="">-- 全部文件夹 --</option>'+folders.map(f=>`<option value="${f.id}">${escHtml(f.name)}</option>`).join('');sel.value='';}
function onAgentPersonaFolderChange(folderID){populatePersonaSelect(folderID||'');}
function populatePersonaSelect(folderID=''){const sel=document.getElementById('agent-persona-select');let list=personas; if(folderID) list=personas.filter(p=>p.folder_id===folderID);sel.innerHTML='<option value="">-- 自定义 --</option>'+list.map(p=>`<option value="${p.id}">${escHtml(p.name)}</option>`).join('');}
function onPersonaSelect(pid){if(!pid)return;const p=personas.find(x=>x.id===pid);if(!p)return;document.getElementById('agent-name').value=p.name;document.getElementById('agent-personality').value=p.personality||'';document.getElementById('agent-color').value=p.avatar_color||'#0ea5e9';if(p.avatar_image){const img=document.getElementById('agent-avatar-preview');img.src=p.avatar_image;img.style.display='block';}}
function previewAgentAvatar(input){if(!input.files||!input.files[0])return;const reader=new FileReader();reader.onload=e=>{const img=document.getElementById('agent-avatar-preview');img.src=e.target.result;img.style.display='block';};reader.readAsDataURL(input.files[0]);}
async function saveAgent(){const name=document.getElementById('agent-name').value.trim();const providerID=document.getElementById('agent-provider').value;const personality=document.getElementById('agent-personality').value.trim();const isAssistant=document.getElementById('agent-is-assistant').checked;const color=document.getElementById('agent-color').value;const avatarImg=document.getElementById('agent-avatar-preview');const avatarImage=avatarImg.style.display!=='none'?avatarImg.src:'';if(!name){notify('请输入角色名称','error');return;}if(!providerID){notify('请选择模型提供商','error');return;}try{if(editingAgentID){await apiFetch('/api/rooms/'+currentRoomID+'/agents/'+editingAgentID,{method:'DELETE'});}const agent=await apiFetch('/api/rooms/'+currentRoomID+'/agents',{method:'POST',body:JSON.stringify({name,provider_id:providerID,personality,avatar_color:color,avatar_image:avatarImage,is_assistant:isAssistant})});closeModal('modal-agent');editingAgentID=null;notify('AI 角色已保存');agentColorCache[agent.id]=color;const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('操作失败: '+e.message,'error');}}
async function saveObserver(){const name=document.getElementById('observer-name').value.trim();const providerID=document.getElementById('observer-provider').value;const personality=document.getElementById('observer-personality').value.trim();const color=document.getElementById('observer-color').value;if(!name){notify('请输入旁观者名称','error');return;}if(!providerID){notify('请选择模型提供商','error');return;}try{if(editingObserverID){await apiFetch('/api/rooms/'+currentRoomID+'/agents/'+editingObserverID,{method:'DELETE'});}await apiFetch('/api/rooms/'+currentRoomID+'/agents',{method:'POST',body:JSON.stringify({name,provider_id:providerID,personality,avatar_color:color,is_observer:true})});closeModal('modal-observer');editingObserverID=null;notify('旁观者已保存');const fullRoom=await apiFetch('/api/rooms/'+currentRoomID);const idx=rooms.findIndex(r=>r.id===currentRoomID);if(idx>=0)rooms[idx]=fullRoom;renderRoomView(fullRoom);renderRoomList();}catch(e){notify('操作失败: '+e.message,'error');}}
(async()=>{await loadProviders();await loadRooms();await loadPersonas();await loadFolders();await loadTemplates();const wsBtn=document.getElementById('btn-ws-debug');if(wsBtn)wsBtn.textContent=wsDebugEnabled()?'WS调试:开':'WS调试:关';const sys=document.getElementById('syscmd-text');if(sys){sys.addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendSysCmd();}});}const obsInput=document.getElementById('observer-chat-input');if(obsInput){obsInput.addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendObserverChat();}});}const obsHeader=document.querySelector('#observer-chat-float .observer-chat-header');if(obsHeader){obsHeader.addEventListener('mousedown',startObserverWindowDrag);}const agentsResizer=document.getElementById('agents-resizer');if(agentsResizer){agentsResizer.addEventListener('mousedown',e=>startPanelResize(e,document.getElementById('agents-panel'),210,520));}const personasResizer=document.getElementById('personas-resizer');if(personasResizer){personasResizer.addEventListener('mousedown',e=>startPanelResize(e,document.getElementById('personas-sidebar'),170,420));}document.addEventListener('mousemove',onObserverWindowDrag);document.addEventListener('mouseup',endObserverWindowDrag);document.addEventListener('mousemove',onObserverFabDrag);document.addEventListener('mouseup',endObserverFabDrag);document.addEventListener('mousemove',onPanelResize);document.addEventListener('mouseup',endPanelResize);document.addEventListener('dblclick',handleAgentCardDoubleClick,true);document.addEventListener('click',()=>{if(Date.now()<contextMenuHoldUntil)return;closeAgentContextMenu();});})();
